sp_widget.client_script:
api.controller = function () {
  var c = this;

  c.formatNumber = function (num) {
    if (typeof num !== 'number') return '0';
    if (num % 1 !== 0) return num.toFixed(1);
    return num.toLocaleString();
  };
};

sp_widget.css:
/* CircleBack Impact Counter Widget */

.cb-impact {
  text-align: center;
  padding: 8px 0 0;
}

/* Stat card — light green background, dark green accents */
.cb-impact-card {
  background: $brand-primary-lighter;
  border-radius: $border-radius-large;
  padding: 24px 16px 20px;
  margin-bottom: 16px;
  border: 1px solid rgba($brand-primary, 0.2);
  transition: transform 0.2s, box-shadow 0.2s;
  &:hover {
    transform: translateY(-2px);
    box-shadow: 0 4px 16px rgba($brand-primary, 0.18);
  }
}

/* Emoji icon */
.cb-impact-icon {
  font-size: 32px;
  line-height: 1;
  margin-bottom: 8px;
}

/* Large bold green number — matches header #2E7D32 */
.cb-impact-value {
  font-size: 36px;
  font-weight: 800;
  color: $brand-primary;
  line-height: 1.1;
  letter-spacing: -0.5px;
}

/* Small label in dark green for contrast */
.cb-impact-label {
  font-size: 13px;
  font-weight: 600;
  color: $brand-primary-dark;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-top: 6px;
}

/* Caption below the cards */
.cb-impact-caption {
  font-size: $font-size-base;
  color: $text-muted;
  font-style: italic;
  margin: 8px 0 0;
  padding-bottom: 0;
}

sp_widget.script:
(function () {
  data.devicesReturned = 0;
  data.kgDiverted = 0;
  data.rewardsIssued = 0;

  try {
    // Counter 1: Return Requests with status = complete
    var grReturns = new GlideAggregate('x_1845356_circle_0_return_request');
    grReturns.addQuery('status', 'complete');
    grReturns.addAggregate('COUNT');
    grReturns.query();
    if (grReturns.next()) {
      data.devicesReturned = parseInt(grReturns.getAggregate('COUNT'), 10) || 0;
    }

    // Counter 2: Sum of weight_kg from all Device Records
    var grWeight = new GlideAggregate('x_1845356_circle_0_device_record');
    grWeight.addAggregate('SUM', 'weight_kg');
    grWeight.query();
    if (grWeight.next()) {
      data.kgDiverted = parseFloat(grWeight.getAggregate('SUM', 'weight_kg')) || 0;
    }

    // Counter 3: Reward Fulfilment records where status = issued or redeemed
    var grRewards = new GlideAggregate('x_1845356_circle_0_reward_fulfilment');
    grRewards.addQuery('status', 'IN', 'issued,redeemed');
    grRewards.addAggregate('COUNT');
    grRewards.query();
    if (grRewards.next()) {
      data.rewardsIssued = parseInt(grRewards.getAggregate('COUNT'), 10) || 0;
    }
  } catch (e) {
    gs.error('CircleBack Impact Counter error: ' + e.message);
  }
})();
